+        let split_x = x + panel_w / 2;
+        draw_vline(
+            buffer,
+            split_x,
+            y + 1,
+            panel_h.saturating_sub(2),
+            '│',
+            Style::fg(Rgba::from_hex("#81ecec").expect("valid")),
