+    fn scan_regex(
+        line: &str,
+        chars: &mut std::iter::Peekable<std::str::CharIndices<'_>>,
+    ) -> (usize, bool) {
+        let mut escaped = false;
+        let mut in_class = false;
+
+        while let Some((idx, ch)) = chars.next() {
+            if escaped {
+                escaped = false;
+                continue;
+            }
+            if ch == '\\' {
+                escaped = true;
+                continue;
+            }
+            if ch == '[' {
+                in_class = true;
+                continue;
+            }
+            if ch == ']' && in_class {
+                in_class = false;
+                continue;
+            }
+            if ch == '/' && !in_class {
+                let mut end_idx = idx + ch.len_utf8();
