+                        end += 1;
+                        base = 16;
+                    }
+                    'b' | 'B' => {
+                        chars.next();
+                        end += 1;
+                        base = 2;
+                    }
+                    'o' | 'O' => {
+                        chars.next();
+                        end += 1;
+                        base = 8;
+                    }
+                    _ => {}
+                }
+            }
+        }
+
+        let is_valid_digit = |ch: char, base: u8| match base {
+            2 => ch == '0' || ch == '1',
+            8 => ch.is_digit(8),
+            16 => ch.is_ascii_hexdigit(),
+            _ => ch.is_ascii_digit(),
