+                    temp.next();
+                    if let Some((_, next_c)) = temp.peek() {
+                        if *next_c == '.' {
+                            break;
+                        }
+                    }
+                }
+                chars.next();
+                end = i + 1;
+            } else {
+                break;
+            }
+        }
+
+        if base == 10 {
+            if let Some(&(i, c)) = chars.peek() {
+                if c == 'e' || c == 'E' {
