+                        if d.is_ascii_digit() || d == '_' {
+                            chars.next();
+                            end = k + 1;
+                        } else {
+                            break;
+                        }
+                    }
+                }
+            }
+        }
+
+        if let Some(&(i, suffix)) = chars.peek() {
+            if suffix == 'n' {
+                chars.next();
+                end = i + 1;
+            }
+        }
