+    assert_eq!(state, LineState::InComment(CommentKind::Block));
+
+    let (tokens, state) = tokenizer.tokenize_line("end */", state);
+    debug!(?tokens, ?state, "block comment end");
+    assert_eq!(state, LineState::Normal);
+}
